using System.Collections;
using UnityEngine;

/// <summary>
/// Sistema de oxigênio para animais terrestres que mergulham
/// (<see cref="AnimalFormData.canDiveAsLand"/> = true).
///
/// Colocar no mesmo GameObject do Player (junto de FormSwitcher e WaterDetector).
///
/// Comportamento:
/// - Enquanto submerso com uma forma que tem <c>canDiveAsLand = true</c>,
///   consome oxigênio à taxa <see cref="AnimalFormData.oxygenDrainRate"/> por
///   segundo.
/// - Ao atingir 0, chama <see cref="PlayerProgress.Damage"/> com dano letal
///   (instakill) — o jogador morre de afogamento.
/// - Ao sair da água (ou ao trocar para uma forma aquática nativa), o oxigênio
///   não é restaurado automaticamente — precisa de uma
///   <see cref="BolhaDeArOxygenPickup"/> ou de sair da água e o sistema reseta.
/// - Ao tocar numa Bolha de Ar (<see cref="BolhaDeArOxygenPickup"/>), o oxigênio
///   restaura para <see cref="AnimalFormData.maxOxygen"/> da forma actual.
///
/// UI:
/// - A mini-HUD de oxigênio deve ouvir <see cref="OxygenChanged"/> para atualizar
///   a barra (valor normalizado 0–1 via <see cref="OxygenRatio"/>).
/// - A HUD só fica visível quando <see cref="IsActive"/> é true.
/// </summary>
[RequireComponent(typeof(WaterDetector))]
[RequireComponent(typeof(FormSwitcher))]
public class OxygenSystem : MonoBehaviour
{
    public static OxygenSystem Instance { get; private set; }

    [Header("Referências (auto-detectadas)")]
    [SerializeField] private WaterDetector waterDetector;
    [SerializeField] private FormSwitcher formSwitcher;

    // ---- Estado ----

    private float _currentOxygen;
    private bool _isDraining;

    // Throttle: OxygenChanged só dispara quando o ratio normalizado muda mais de 1%,
    // em vez de a cada frame — evita overdispatch para a HUD.
    private float _lastReportedRatio = -1f;
    private const float OxygenChangedThreshold = 0.01f;

    /// <summary>True quando o sistema está activo (forma terrestre + submerso).</summary>
    public bool IsActive { get; private set; }

    /// <summary>Oxigênio actual em segundos.</summary>
    public float CurrentOxygen => _currentOxygen;

    /// <summary>Oxigênio máximo da forma actual (AnimalFormData.maxOxygen).</summary>
    public float MaxOxygen { get; private set; }

    /// <summary>Razão de oxigênio (0 = vazio, 1 = cheio) — para a mini-HUD.</summary>
    public float OxygenRatio => MaxOxygen > 0f ? Mathf.Clamp01(_currentOxygen / MaxOxygen) : 0f;

    // ---- Eventos ----

    /// <summary>Disparado quando o oxigênio muda (actual, máximo, isActive) — mini-HUD liga-se aqui.</summary>
    public event System.Action<float, float, bool> OxygenChanged;

    /// <summary>Disparado ao morrer de afogamento — antes de chamar PlayerProgress.Damage.</summary>
    public event System.Action OnDrown;

    // ---- Unity ----

    private void Awake()
    {
        if (Instance != null && Instance != this) { Destroy(this); return; }
        Instance = this;

        if (waterDetector == null) waterDetector = GetComponent<WaterDetector>();
        if (formSwitcher == null) formSwitcher = GetComponent<FormSwitcher>();
    }

    private void OnEnable()
    {
        if (formSwitcher != null) formSwitcher.OnFormApplied += OnFormApplied;
        if (waterDetector != null)
        {
            waterDetector.EnteredSubmerged += OnEnteredSubmerged;
            waterDetector.ExitedSubmerged += OnExitedSubmerged;
        }
    }

    private void OnDisable()
    {
        if (formSwitcher != null) formSwitcher.OnFormApplied -= OnFormApplied;
        if (waterDetector != null)
        {
            waterDetector.EnteredSubmerged -= OnEnteredSubmerged;
            waterDetector.ExitedSubmerged -= OnExitedSubmerged;
        }
    }

    private void Update()
    {
        if (!_isDraining) return;

        var form = formSwitcher != null ? formSwitcher.CurrentForm : null;
        if (form == null || !form.canDiveAsLand) { StopDraining(); return; }

        _currentOxygen -= form.oxygenDrainRate * Time.deltaTime;

        if (_currentOxygen <= 0f)
        {
            _currentOxygen = 0f;
            NotifyOxygenChanged(force: true);
            Drown();
            return;
        }

        NotifyOxygenChanged();
    }

    // ---- Callbacks ----

    private void OnFormApplied(AnimalFormData form)
    {
        if (form == null) return;

        if (form.canDiveAsLand)
        {
            MaxOxygen = form.maxOxygen;
            // Ao trocar de forma debaixo de água, repõe o oxigênio — a nova
            // forma "tem os pulmões cheios". (Comportamento configurável se necessário.)
            if (_isDraining)
                RestoreOxygen();
        }
        else
        {
            // Forma aquática nativa ou terrestre sem mergulho → sistema inactivo.
            StopDraining();
        }
    }

    private void OnEnteredSubmerged()
    {
        var form = formSwitcher != null ? formSwitcher.CurrentForm : null;
        if (form == null || !form.canDiveAsLand) return;

        MaxOxygen = form.maxOxygen;
        _currentOxygen = MaxOxygen;
        StartDraining();
    }

    private void OnExitedSubmerged()
    {
        // Ao sair da água: restaura o oxigênio (voltou ao ar).
        RestoreOxygen();
        StopDraining();
    }

    // ---- API pública ----

    /// <summary>
    /// Restaura o oxigênio para o máximo (chamado por <see cref="BolhaDeArOxygenPickup"/>
    /// ou ao sair da água). Dispara <see cref="OxygenChanged"/>.
    /// </summary>
    public void RestoreOxygen()
    {
        var form = formSwitcher != null ? formSwitcher.CurrentForm : null;
        if (form != null && form.canDiveAsLand)
            MaxOxygen = form.maxOxygen;

        _currentOxygen = MaxOxygen;
        NotifyOxygenChanged(force: true);
    }

    // ---- Internos ----

    private void StartDraining()
    {
        _isDraining = true;
        IsActive = true;
        NotifyOxygenChanged(force: true);
    }

    private void StopDraining()
    {
        _isDraining = false;
        IsActive = false;
        NotifyOxygenChanged(force: true);
    }

    /// <summary>
    /// Dispara OxygenChanged apenas quando o ratio normalizado muda mais de
    /// <see cref="OxygenChangedThreshold"/> (1%) ou quando forçado (mudanças de
    /// estado, restore, morte). Evita overdispatch para a HUD a cada frame.
    /// </summary>
    private void NotifyOxygenChanged(bool force = false)
    {
        float ratio = OxygenRatio;
        if (!force && Mathf.Abs(ratio - _lastReportedRatio) < OxygenChangedThreshold) return;

        _lastReportedRatio = ratio;
        OxygenChanged?.Invoke(_currentOxygen, MaxOxygen, IsActive);
    }

    private void Drown()
    {
        StopDraining();
        OnDrown?.Invoke();

        // Dano letal (instakill): tira todos os corações de uma vez.
        var progress = PlayerProgress.Instance;
        if (progress != null)
            progress.Damage(progress.maxHearts + 1);
    }
}
